import { createClient } from "@/lib/supabase/server";
import { redirect } from "next/navigation";
import type { Metadata } from "next";
import TelegramAutomations from "@/components/dashboard/TelegramAutomations";

export const metadata: Metadata = { title: "Telegram Bot" };

export default async function TelegramPage() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) redirect("/auth/login");

  const { data: therapist } = await supabase
    .from("therapists")
    .select("id, telegram_bot_token, telegram_bot_username, telegram_chat_id")
    .eq("user_id", user.id)
    .single();
  if (!therapist) redirect("/auth/login");

  // Fetch telegram config
  const { data: config } = await supabase
    .from("telegram_configs")
    .select("*")
    .eq("therapist_id", therapist.id)
    .single();

  const automations = (config?.automations ?? {}) as Record<string, boolean>;

  const isBotConfigured = !!therapist.telegram_bot_token;

  return (
    <div className="p-8 max-w-6xl mx-auto w-full animate-[fadeUp_.4s_ease-out_both]">
      {/* Header */}
      <div className="mb-8">
        <h1 className="font-[family-name:var(--font-display)] text-4xl font-light text-[var(--color-text-primary)] tracking-tight">
          Telegram Bot
        </h1>
        <p className="text-[14px] text-[var(--color-text-muted)] mt-1 font-light">
          Configure e monitore o bot de atendimento no Telegram
        </p>
      </div>

      {/* Status card */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <StatusCard
          label="Status"
          value={isBotConfigured ? "Ativo" : "Desconectado"}
          tone={isBotConfigured ? "brand" : "danger"}
          icon={isBotConfigured ? "✅" : "❌"}
          delay={0}
        />
        <StatusCard
          label="Bot Username"
          value={
            therapist.telegram_bot_username
              ? `@${therapist.telegram_bot_username}`
              : "—"
          }
          tone="sky"
          icon="🤖"
          delay={0.05}
        />
        <StatusCard
          label="Chat ID"
          value={
            therapist.telegram_chat_id
              ? String(therapist.telegram_chat_id)
              : "—"
          }
          tone="muted"
          icon="💬"
          delay={0.1}
        />
      </div>

      {/* Setup instructions */}
      {!isBotConfigured && (
        <div className="bg-[#fbbf24]/5 border border-[#fbbf24]/20 rounded-2xl p-7 mb-8 animate-[fadeUp_.4s_ease-out_.15s_both]">
          <div className="text-[16px] text-[#fbbf24] font-medium mb-4 flex items-center gap-2">
            <span>⚙️</span> Configuração Necessária
          </div>
          <div className="text-[14px] text-[var(--color-text-secondary)] leading-relaxed font-light">
            <p className="mb-3">
              Para ativar o bot do Telegram, siga os passos:
            </p>
            <ol className="list-decimal pl-5 flex flex-col gap-2.5">
              <li>Abra o Telegram e fale com o <span className="text-[var(--color-brand)] font-medium">@BotFather</span></li>
              <li>Envie <code className="bg-[var(--color-surface-hover)] px-2 py-0.5 rounded font-mono text-[12px] text-[var(--color-text-primary)]">/newbot</code> e siga as instruções</li>
              <li>Copie o <strong>Token do Bot</strong> fornecido</li>
              <li>Acesse <span className="text-[var(--color-brand)] font-medium">Configurações → Integrações</span> e cole o token</li>
            </ol>
          </div>
        </div>
      )}

      {/* Automations */}
      <div className="bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-7 mb-6 glass-panel animate-[fadeUp_.4s_ease-out_.2s_both]">
        <h2 className="font-[family-name:var(--font-display)] text-[22px] font-light text-[var(--color-text-primary)] mb-6">
          Automações
        </h2>
        <div className="flex flex-col gap-0 border border-[var(--color-border-subtle)] rounded-xl overflow-hidden">
          <TelegramAutomations initialAutomations={automations} />
        </div>
      </div>

      {/* Commands reference */}
      <div className="bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-7 glass-panel animate-[fadeUp_.4s_ease-out_.25s_both]">
        <h2 className="font-[family-name:var(--font-display)] text-[22px] font-light text-[var(--color-text-primary)] mb-5">
          Comandos do Bot
        </h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {[
            { cmd: "/start", desc: "Inicia conversa com paciente" },
            { cmd: "/agendar", desc: "Agendar nova sessão" },
            { cmd: "/sessoes", desc: "Ver próximas sessões" },
            { cmd: "/cancelar", desc: "Cancelar sessão" },
            { cmd: "/pagar", desc: "Link de pagamento" },
            { cmd: "/falar", desc: "Conversar com IA" },
            { cmd: "/ajuda", desc: "Lista de comandos" },
          ].map((c) => (
            <div
              key={c.cmd}
              className="flex items-center gap-3 px-4 py-3 bg-[var(--color-surface-hover)] rounded-xl border border-[var(--color-border-subtle)] hover:border-[var(--color-border-strong)] transition-colors group"
            >
              <code className="text-[12px] text-[var(--color-brand)] font-mono font-medium min-w-[70px]">
                {c.cmd}
              </code>
              <span className="text-[13px] text-[var(--color-text-muted)] group-hover:text-[var(--color-text-secondary)] transition-colors">
                {c.desc}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── Helpers ───────────────────────────────────────────────────────
function StatusCard({
  label,
  value,
  tone,
  icon,
  delay = 0,
}: {
  label: string;
  value: string;
  tone: "brand" | "danger" | "sky" | "muted";
  icon: string;
  delay?: number;
}) {
  const delayClass: Record<string, string> = {
    "0": "[animation-delay:0s]",
    "0.05": "[animation-delay:0.05s]",
    "0.1": "[animation-delay:0.1s]",
  };

  const toneClasses: Record<
    "brand" | "danger" | "sky" | "muted",
    { glow: string; value: string }
  > = {
    brand: {
      glow: "bg-[var(--color-brand)]",
      value: "text-[var(--color-brand)]",
    },
    danger: {
      glow: "bg-[#f87171]",
      value: "text-[#f87171]",
    },
    sky: {
      glow: "bg-[#38bdf8]",
      value: "text-[#38bdf8]",
    },
    muted: {
      glow: "bg-[var(--color-text-secondary)]",
      value: "text-[var(--color-text-secondary)]",
    },
  };

  const toneCfg = toneClasses[tone];

  return (
    <div
      className={`bg-[var(--color-surface)] border border-[var(--color-border-subtle)] rounded-2xl p-6 glass-panel relative overflow-hidden group hover:border-[var(--color-border-strong)] transition-all duration-300 animate-[fadeUp_.4s_ease-out_both] ${delayClass[String(delay)] ?? ""}`}
    >
      <div
        className={`absolute top-0 right-0 w-32 h-32 opacity-[0.03] rounded-bl-full group-hover:opacity-[0.06] transition-opacity duration-500 pointer-events-none ${toneCfg.glow}`}
      />
      <div className="flex items-center gap-2 mb-3 relative z-10">
        <span className="text-[16px]">{icon}</span>
        <span className="text-[11px] text-[var(--color-text-muted)] uppercase tracking-widest font-medium">
          {label}
        </span>
      </div>
      <div
        className={`font-[family-name:var(--font-display)] text-[22px] font-light relative z-10 truncate ${toneCfg.value}`}
      >
        {value}
      </div>
    </div>
  );
}
